adlock.\n\tmu sync.RWMutex\n\n\t// victims are watcher batches that were blocked on the watch channel\n\tvictims []watcherBatch\n\tvictimc chan struct{}\n\n\t// contains all unsynced watchers that needs to sync with events that have happened\n\tunsynced watcherGroup\n\n\t// contains all synced watchers that are in sync with the progress of the store.\n\t// The key of the map is the key that the watcher watches on.\n\tsynced watcherGroup\n\n\tstopc chan struct{}\n\twg    sync.WaitGroup\n}\n\nvar _ WatchableKV = (*watchableStore)(nil)\n\n// cancelFunc updates unsynced and synced maps when running\n// cancel operations.\ntype cancelFunc func()\n\nfunc New(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) WatchableKV {\n\ts := newWatchableStore(lg, b, le, cfg)\n\ts.wg.Add(2)\n\tgo s.syncWatchersLoop()\n\tgo s.syncVictimsLoop()\n\treturn s\n}\n\nfunc newWatchableStore(lg *zap.Logger, b backend.Backend, le lease.Lessor, cfg StoreConfig) *watchableStore {\n\tif lg == nil {\n\t\tlg = zap.NewNop()\n\t}\n\ts := &watchableStore{\n\t\tstore:    NewStore(lg, b, le, cfg),\n\t\tvictimc:  make(chan struct{}, 1),\n\t\tunsynced: newWatcherGroup(),\n\t\tsynced:   newWatcherGroup(),\n\t\tstopc:    make(chan struct{}),\n\t}\n\ts.store.ReadView = &readView{s}\n\ts.store.WriteView = &writeView{s}\n\tif s.le != nil {\n\t\t// use this store as the deleter so revokes trigger watch events\n\t\ts.le.SetRangeDeleter(func() lease.TxnDelete { return s.Write(traceutil.TODO()) })\n\t}\n\treturn s\n}\n\nfunc (s *watchableStore) Close() error {\n\tclose(s.stopc)\n\ts.wg.Wait()\n\treturn s.store.Close()\n}\n\nfunc (s *watchableStore) NewWatchStream() WatchStream {\n\twatchStreamGauge.Inc()\n\treturn &watchStream{\n\t\twatchable: s,\n\t\tch:        make(chan WatchResponse, chanBufLen),\n\t\tcancels:   make(map[WatchID]cancelFunc),\n\t\twatchers:  make(map[WatchID]*watcher),\n\t}\n}\n\nfunc (s *watchableStore) watch(key, end []byte, startRev int64, id WatchID, ch chan<- WatchResponse, fcs ...FilterFunc) (*watcher, cancelFunc) {\n\twa := &watcher{\n\t\tkey:      key,\n\t\tend:      end,\n\t\tstartRev: startRev,\n\t\tminRev:   startRev,\n\t\tid:       id,\n\t\tch:       ch,\n\t\tfcs:      fcs,\n\t}\n\n\ts.mu.Lock()\n\ts.revMu.RLock()\n\tsynced := startRev > s.store.currentRev || startRev == 0\n\tif synced {\n\t\twa.minRev = s.store.currentRev + 1\n\t\tif startRev > wa.minRev {\n\t\t\twa.minRev = startRev\n\t\t}\n\t\ts.synced.add(wa)\n\t} else {\n\t\tslowWatcherGauge.Inc()\n\t\ts.unsynced.add(wa)\n\t}\n\ts.revMu.RUnlock()\n\ts.mu.Unlock()\n\n\twatcherGauge.Inc()\n\n\treturn wa, func() { s.cancelWatcher(wa) }\n}\n\n// cancelWatcher removes references of the watcher from the watchableStore\nfunc (s *watchableStore) cancelWatcher(wa *watcher) {\n\tfor {\n\t\ts.mu.Lock()\n\t\tif s.unsynced.delete(wa) {\n\t\t\tslowWatcherGauge.Dec()\n\t\t\twatcherGauge.Dec()\n\t\t\tbreak\n\t\t} else if s.synced.delete(wa) {\n\t\t\twatcherGauge.Dec()\n\t\t\tbreak\n\t\t} else if wa.ch == nil {\n\t\t\t// already canceled (e.g., cancel/close race)\n\t\t\tbreak\n\t\t} else if wa.compacted {\n\t\t\twatcherGauge.Dec()\n\t\t\tbreak\n\t\t}\n\n\t\tif !wa.victim {\n\t\t\ts.mu.Unlock()\n\t\t\tpanic(\"watcher not victim but not in watch groups\")\n\t\t}\n\n\t\tvar victimBatch watcherBatch\n\t\tfor _, wb := range s.victims {\n\t\t\tif wb[wa] != nil {\n\t\t\t\tvictimBatch = wb\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t\tif victimBatch != nil {\n\t\t\tslowWatcherGauge.Dec()\n\t\t\twatcherGauge.Dec()\n\t\t\tdelete(victimBatch, wa)\n\t\t\tbreak\n\t\t}\n\n\t\t// victim being processed so not accessible; retry\n\t\ts.mu.Unlock()\n\t\ttime.Sleep(time.Millisecond)\n\t}\n\n\twa.ch = nil\n\ts.mu.Unlock()\n}\n\nfunc (s *watchableStore) Restore(b backend.Backend) error {\n\ts.mu.Lock()\n\tdefer s.mu.Unlock()\n\terr := s.store.Restore(b)\n\tif err != nil {\n\t\treturn err\n\t}\n\n\tfor wa := range s.synced.watchers {\n\t\twa.restore = true\n\t\ts.unsynced.add(wa)\n\t}\n\ts.synced = newWatcherGroup()\n\treturn nil\n}\n\n// syncWatchersLoop syncs the watcher in the unsynced map every 100ms.\nfunc (s *watchableStore) syncWatchersLoop() {\n\tdefer s.wg.Done()\n\n\tdelayTicker := time.NewTicker(watchResyncPeriod)\n\tdefer delayTicker.Stop()\n\tvar evs []mvccpb.Event\n\n\tfor {\n\t\ts.mu.RLock()\n\t\tst := time.Now()\n\t\tlastUnsyncedWatchers := s.unsynced.size()\n\t\ts.mu.RUnlock()\n\n\t\tunsyncedWatchers := 0\n\t\tif lastUnsyncedWatchers > 0 {\n\t\t\tunsyncedWatchers, evs = s.syncWatchers(evs)\n\t\t}\n\t\tsyncDuration := time.Since(st)\n\n\t\tdelayTicker.Reset(watchResyncPeriod)\n\t\t// more work pending?\n\t\tif unsyncedWatchers != 0 && lastUnsyncedWatchers > unsyncedWatchers {\n\t\t\t// be fair to other store operations by yielding time taken\n\t\t\tdelayTicker.Reset(syncDuration)\n\t\t}\n\n\t\tselect {\n\t\tcase <-delayTicker.C:\n\t\tcase <-s.stopc:\n\t\t\treturn\n\t\t}\n\t}\n}\n\n// syncVictimsLoop tries to write precomputed watcher responses to\n// watchers that had a blocked watcher channel\nfunc (s *watchableStore) syncVictimsLoop() {\n\tdefer s.wg.Done()\n\n\tfor {\n\t\tfor s.moveVictims() != 0 {\n\t\t\t// try to update all victim watchers\n\t\t}\n\t\ts.mu.RLock()\n\t\tisEmpty := len(s.victims) == 0\n\t\ts.mu.RUnlock()\n\n\t\tvar tickc <-chan time.Time\n\t\tif !isEmpty {\n\t\t\ttickc = time.After(10 * time.Millisecond)\n\t\t}\n\n\t\tselect {\n\t\tcase <-tickc:\n\t\tcase <-s.victimc:\n\t\tcase <-s.stopc:\n\t\t\treturn\n\t\t}\n\t}\n}\n\n// moveVictims tries to update watches with already pending event data\nfunc (s *watchableStore) moveVictims() (moved int) {\n\ts.mu.Lock()\n\tvictims := s.victims\n\ts.victims = nil\n\ts.mu.Unlock()\n\n\tvar newVictim watcherBatch\n\tfor _, wb := range victims {\n\t\t// try to send responses again\n\t\tfor w, eb := range wb {\n\t\t\t// watcher has observed the store up to, but not including, w.minRev\n\t\t\trev := w.minRev - 1\n\t\t\tif !w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {\n\t\t\t\tif newVictim == nil {\n\t\t\t\t\tnewVictim = make(watcherBatch)\n\t\t\t\t}\n\t\t\t\tnewVictim[w] = eb\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tpendingEventsGauge.Add(float64(len(eb.evs)))\n\t\t\tmoved++\n\t\t}\n\n\t\t// assign completed victim watchers to unsync/sync\n\t\ts.mu.Lock()\n\t\ts.store.revMu.RLock()\n\t\tcurRev := s.store.currentRev\n\t\tfor w, eb := range wb {\n\t\t\tif newVictim != nil && newVictim[w] != nil {\n\t\t\t\t// couldn't send watch response; stays victim\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tw.victim = false\n\t\t\tif eb.moreRev != 0 {\n\t\t\t\tw.minRev = eb.moreRev\n\t\t\t}\n\t\t\tif w.minRev <= curRev {\n\t\t\t\ts.unsynced.add(w)\n\t\t\t} else {\n\t\t\t\tslowWatcherGauge.Dec()\n\t\t\t\ts.synced.add(w)\n\t\t\t}\n\t\t}\n\t\ts.store.revMu.RUnlock()\n\t\ts.mu.Unlock()\n\t}\n\n\tif len(newVictim) > 0 {\n\t\ts.mu.Lock()\n\t\ts.victims = append(s.victims, newVictim)\n\t\ts.mu.Unlock()\n\t}\n\n\treturn moved\n}\n\n// syncWatchers syncs unsynced watchers by:\n//  1. choose a set of watchers from the unsynced watcher group\n//  2. iterate over the set to get the minimum revision and remove compacted watchers\n//  3. use minimum revision to get all key-value pairs and send those events to watchers\n//  4. remove synced watchers in set from unsynced group and move to synced group\nfunc (s *watchableStore) syncWatchers(evs []mvccpb.Event) (int, []mvccpb.Event) {\n\ts.mu.Lock()\n\tdefer s.mu.Unlock()\n\n\tif s.unsynced.size() == 0 {\n\t\treturn 0, []mvccpb.Event{}\n\t}\n\n\ts.store.revMu.RLock()\n\tdefer s.store.revMu.RUnlock()\n\n\t// in order to find key-value pairs from unsynced watchers, we need to\n\t// find min revision index, and these revisions can be used to\n\t// query the backend store of key-value pairs\n\tcurRev := s.store.currentRev\n\tcompactionRev := s.store.compactMainRev\n\n\twg, minRev := s.unsynced.choose(maxWatchersPerSync, curRev, compactionRev)\n\tevs = rangeEventsWithReuse(s.store.lg, s.store.b, evs, minRev, curRev+1)\n\n\tvictims := make(watcherBatch)\n\twb := newWatcherBatch(wg, evs)\n\tfor w := range wg.watchers {\n\t\tif w.minRev < compactionRev {\n\t\t\t// Skip the watcher that failed to send compacted watch response due to w.ch is full.\n\t\t\t// Next retry of syncWatchers would try to resend the compacted watch response to w.ch\n\t\t\tcontinue\n\t\t}\n\t\tw.minRev = max(curRev+1, w.minRev)\n\n\t\teb, ok := wb[w]\n\t\tif !ok {\n\t\t\t// bring un-notified watcher to synced\n\t\t\ts.synced.add(w)\n\t\t\ts.unsynced.delete(w)\n\t\t\tcontinue\n\t\t}\n\n\t\tif eb.moreRev != 0 {\n\t\t\tw.minRev = eb.moreRev\n\t\t}\n\n\t\tif w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: curRev}) {\n\t\t\tpendingEventsGauge.Add(float64(len(eb.evs)))\n\t\t} else {\n\t\t\tw.victim = true\n\t\t}\n\n\t\tif w.victim {\n\t\t\tvictims[w] = eb\n\t\t} else {\n\t\t\tif eb.moreRev != 0 {\n\t\t\t\t// stay unsynced; more to read\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\ts.synced.add(w)\n\t\t}\n\t\ts.unsynced.delete(w)\n\t}\n\ts.addVictim(victims)\n\n\tvsz := 0\n\tfor _, v := range s.victims {\n\t\tvsz += len(v)\n\t}\n\tslowWatcherGauge.Set(float64(s.unsynced.size() + vsz))\n\n\treturn s.unsynced.size(), evs\n}\n\n// rangeEventsWithReuse returns events in range [minRev, maxRev), while reusing already provided events.\nfunc rangeEventsWithReuse(lg *zap.Logger, b backend.Backend, evs []mvccpb.Event, minRev, maxRev int64) []mvccpb.Event {\n\tif len(evs) == 0 {\n\t\treturn rangeEvents(lg, b, minRev, maxRev)\n\t}\n\t// append from left\n\tif evs[0].Kv.ModRevision > minRev {\n\t\tevs = append(rangeEvents(lg, b, minRev, evs[0].Kv.ModRevision), evs...)\n\t}\n\t// cut from left\n\tprefixIndex := 0\n\tfor prefixIndex < len(evs) && evs[prefixIndex].Kv.ModRevision < minRev {\n\t\tprefixIndex++\n\t}\n\tevs = evs[prefixIndex:]\n\n\tif len(evs) == 0 {\n\t\treturn rangeEvents(lg, b, minRev, maxRev)\n\t}\n\t// append from right\n\tif evs[len(evs)-1].Kv.ModRevision+1 < maxRev {\n\t\tevs = append(evs, rangeEvents(lg, b, evs[len(evs)-1].Kv.ModRevision+1, maxRev)...)\n\t}\n\t// cut from right\n\tsuffixIndex := len(evs) - 1\n\tfor suffixIndex >= 0 && evs[suffixIndex].Kv.ModRevision >= maxRev {\n\t\tsuffixIndex--\n\t}\n\tevs = evs[:suffixIndex+1]\n\treturn evs\n}\n\n// rangeEvents returns events in range [minRev, maxRev).\nfunc rangeEvents(lg *zap.Logger, b backend.Backend, minRev, maxRev int64) []mvccpb.Event {\n\tif minRev < 0 {\n\t\tlg.Warn(\"Unexpected negative revision range start\", zap.Int64(\"minRev\", minRev))\n\t\tminRev = 0\n\t}\n\tminBytes, maxBytes := NewRevBytes(), NewRevBytes()\n\tminBytes = RevToBytes(Revision{Main: minRev}, minBytes)\n\tmaxBytes = RevToBytes(Revision{Main: maxRev}, maxBytes)\n\n\t// UnsafeRange returns keys and values. And in boltdb, keys are revisions.\n\t// values are actual key-value pairs in backend.\n\ttx := b.ReadTx()\n\ttx.RLock()\n\trevs, vs := tx.UnsafeRange(schema.Key, minBytes, maxBytes, 0)\n\tevs := kvsToEvents(lg, revs, vs)\n\t// Must unlock after kvsToEvents, because vs (come from boltdb memory) is not deep copy.\n\t// We can only unlock after Unmarshal, which will do deep copy.\n\t// Otherwise we will trigger SIGSEGV during boltdb re-mmap.\n\ttx.RUnlock()\n\treturn evs\n}\n\n// kvsToEvents gets all events for the watchers from all key-value pairs\nfunc kvsToEvents(lg *zap.Logger, revs, vals [][]byte) (evs []mvccpb.Event) {\n\tfor i, v := range vals {\n\t\tvar kv mvccpb.KeyValue\n\t\tif err := kv.Unmarshal(v); err != nil {\n\t\t\tlg.Panic(\"failed to unmarshal mvccpb.KeyValue\", zap.Error(err))\n\t\t}\n\n\t\tty := mvccpb.Event_PUT\n\t\tif isTombstone(revs[i]) {\n\t\t\tty = mvccpb.Event_DELETE\n\t\t\t// patch in mod revision so watchers won't skip\n\t\t\tkv.ModRevision = BytesToRev(revs[i]).Main\n\t\t}\n\t\tevs = append(evs, mvccpb.Event{Kv: &kv, Type: ty})\n\t}\n\treturn evs\n}\n\n// notify notifies the fact that given event at the given rev just happened to\n// watchers that watch on the key of the event.\nfunc (s *watchableStore) notify(rev int64, evs []mvccpb.Event) {\n\tvictim := make(watcherBatch)\n\tfor w, eb := range newWatcherBatch(&s.synced, evs) {\n\t\tif eb.revs != 1 {\n\t\t\ts.store.lg.Panic(\n\t\t\t\t\"unexpected multiple revisions in watch notification\",\n\t\t\t\tzap.Int(\"number-of-revisions\", eb.revs),\n\t\t\t)\n\t\t}\n\t\tif w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {\n\t\t\tpendingEventsGauge.Add(float64(len(eb.evs)))\n\t\t} else {\n\t\t\t// move slow watcher to victims\n\t\t\tw.victim = true\n\t\t\tvictim[w] = eb\n\t\t\ts.synced.delete(w)\n\t\t\tslowWatcherGauge.Inc()\n\t\t}\n\t\t// always update minRev\n\t\t// in case 'send' returns true and watcher stays synced, this is needed for Restore when all watchers become unsynced\n\t\t// in case 'send' returns false, this is needed for syncWatchers\n\t\tw.minRev = rev + 1\n\t}\n\ts.addVictim(victim)\n}\n\nfunc (s *watchableStore) addVictim(victim watcherBatch) {\n\tif len(victim) == 0 {\n\t\treturn\n\t}\n\ts.victims = append(s.victims, victim)\n\tselect {\n\tcase s.victimc <- struct{}{}:\n\tdefault:\n\t}\n}\n\nfunc (s *watchableStore) rev() int64 { return s.store.Rev() }\n\nfunc (s *watchableStore) progress(w *watcher) {\n\ts.progressIfSync(map[WatchID]*watcher{w.id: w}, w.id)\n}\n\nfunc (s *watchableStore) progressAll(watchers map[WatchID]*watcher) bool {\n\treturn s.progressIfSync(watchers, clientv3.InvalidWatchID)\n}\n\nfunc (s *watchableStore) progressIfSync(watchers map[WatchID]*watcher, responseWatchID WatchID) bool {\n\ts.mu.RLock()\n\tdefer s.mu.RUnlock()\n\n\trev := s.rev()\n\t// Any watcher unsynced?\n\tfor _, w := range watchers {\n\t\tif _, ok := s.synced.watchers[w]; !ok {\n\t\t\treturn false\n\t\t}\n\t\tif rev < w.startRev {\n\t\t\treturn false\n\t\t}\n\t}\n\n\t// If all watchers are synchronised, send out progress\n\t// notification on first watcher. Note that all watchers\n\t// should have the same underlying stream, and the progress\n\t// notification will be broadcasted client-side if required\n\t// (see dispatchEvent in client/v3/watch.go)\n\tfor _, w := range watchers {\n\t\tw.send(WatchResponse{WatchID: responseWatchID, Revision: rev})\n\t\treturn true\n\t}\n\treturn true\n}\n\ntype watcher struct {\n\t// the watcher key\n\tkey []byte\n\t// end indicates the end of the range to watch.\n\t// If end is set, the watcher is on a range.\n\tend []byte\n\n\t// victim is set when ch is blocked and undergoing victim processing\n\tvictim bool\n\n\t// compacted is set when the watcher is removed because of compaction\n\tcompacted bool\n\n\t// restore is true when the watcher is being restored from leader snapshot\n\t// which means that this watcher has just been moved from \"synced\" to \"unsynced\"\n\t// watcher group, possibly with a future revision when it was first added\n\t// to the synced watcher\n\t// \"unsynced\" watcher revision must always be <= current revision,\n\t// except when the watcher were to be moved from \"synced\" watcher group\n\trestore bool\n\n\tstartRev int64\n\t// minRev is the minimum revision update the watcher will accept\n\tminRev int64\n\tid     WatchID\n\n\tfcs []FilterFunc\n\t// a chan to send out the watch response.\n\t// The chan might be shared with other watchers.\n\tch chan<- WatchResponse\n}\n\nfunc (w *watcher) send(wr WatchResponse) bool {\n\tprogressEvent := len(wr.Events) == 0\n\n\tif len(w.fcs) != 0 {\n\t\tne := make([]mvccpb.Event, 0, len(wr.Events))\n\t\tfor i := range wr.Events {\n\t\t\tfiltered := false\n\t\t\tfor _, filter := range w.fcs {\n\t\t\t\tif filter(wr.Events[i]) {\n\t\t\t\t\tfiltered = true\n\t\t\t\t\tbreak\n\t\t\t\t}\n\t\t\t}\n\t\t\tif !filtered {\n\t\t\t\tne = append(ne, wr.Events[i])\n\t\t\t}\n\t\t}\n\t\twr.Events = ne\n\t}\n\n\tverify.Verify(\"Event.ModRevision is less than the w.startRev for watchID\", func() (bool, map[string]any) {\n\t\tif w.startRev > 0 {\n\t\t\tfor _, ev := range wr.Events {\n\t\t\t\tif ev.Kv.ModRevision < w.startRev {\n\t\t\t\t\treturn false, map[string]any{\n\t\t\t\t\t\t\"Event.ModRevision\": ev.Kv.ModRevision,\n\t\t\t\t\t\t\"w.startRev\":        w.startRev,\n\t\t\t\t\t\t\"watchID\":           w.id,\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t\treturn true, nil\n\t})\n\n\t// if all events are filtered out, we should send nothing.\n\tif !progressEvent && len(wr.Events) == 0 {\n\t\treturn true\n\t}\n\tselect {\n\tcase w.ch <- wr:\n\t\treturn true\n\tdefault:\n\t\treturn false\n\t}\n}\n", "numLines": 644, "startLine": 1, "totalLines": 644}}

