   263→		for s.moveVictims() != 0 {
   264→			// try to update all victim watchers
   265→		}
   266→		s.mu.RLock()
   267→		isEmpty := len(s.victims) == 0
   268→		s.mu.RUnlock()
   269→
   270→		var tickc <-chan time.Time
   271→		if !isEmpty {
   272→			tickc = time.After(10 * time.Millisecond)
   273→		}
   274→
   275→		select {
   276→		case <-tickc:
   277→		case <-s.victimc:
   278→		case <-s.stopc:
   279→			return
   280→		}
   281→	}
   282→}
