   284→// moveVictims tries to update watches with already pending event data
   285→func (s *watchableStore) moveVictims() (moved int) {
   286→	s.mu.Lock()
   287→	victims := s.victims
   288→	s.victims = nil
   289→	s.mu.Unlock()
   290→
   291→	var newVictim watcherBatch
   292→	for _, wb := range victims {
   293→		// try to send responses again
   294→		for w, eb := range wb {
   295→			// watcher has observed the store up to, but not including, w.minRev
   296→			rev := w.minRev - 1
   297→			if !w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {
   298→				if newVictim == nil {
   299→					newVictim = make(watcherBatch)
   300→				}
   301→				newVictim[w] = eb
   302→				continue
   303→			}
   304→			pendingEventsGauge.Add(float64(len(eb.evs)))
   305→			moved++
   306→		}
   307→
   308→		// assign completed victim watchers to unsync/sync
   309→		s.mu.Lock()
   310→		s.store.revMu.RLock()
   311→		curRev := s.store.currentRev
   312→		for w, eb := range wb {
   313→			if newVictim != nil && newVictim[w] != nil {
   314→				// couldn't send watch response; stays victim
   315→				continue
   316→			}
   317→			w.victim = false
   318→			if eb.moreRev != 0 {
   319→				w.minRev = eb.moreRev
   320→			}
   321→			if w.minRev <= curRev {
   322→				s.unsynced.add(w)
   323→			} else {
   324→				slowWatcherGauge.Dec()
   325→				s.synced.add(w)
   326→			}
   327→		}
   328→		s.store.revMu.RUnlock()
   329→		s.mu.Unlock()
   330→	}
   331→
   332→	if len(newVictim) > 0 {
   333→		s.mu.Lock()
   334→		s.victims = append(s.victims, newVictim)
   335→		s.mu.Unlock()
   336→	}
   337→
   338→	return moved
   339→}
   340→
   341→// syncWatchers syncs unsynced watchers by:
   342→//  1. choose a set of watchers from the unsynced watcher group
   343→//  2. iterate over the set to get the minimum revision and remove compacted watchers
   344→//  3. use minimum revision to get all key-value pairs and send those events to watchers
   345→//  4. remove synced watchers in set from unsynced group and move to synced group
   346→func (s *watchableStore) syncWatchers(evs []mvccpb.Event) (int, []mvccpb.Event) {
   347→	s.mu.Lock()
   348→	defer s.mu.Unlock()
   349→
   350→	if s.unsynced.size() == 0 {
   351→		return 0, []mvccpb.Event{}
   352→	}
   353→
   354→	s.store.revMu.RLock()
   355→	defer s.store.revMu.RUnlock()
   356→
   357→	// in order to find key-value pairs from unsynced watchers, we need to
   358→	// find min revision index, and these revisions can be used to
   359→	// query the backend store of key-value pairs
   360→	curRev := s.store.currentRev
   361→	compactionRev := s.store.compactMainRev
   362→
   363→	wg, minRev := s.unsynced.choose(maxWatchersPerSync, curRev, compactionRev)
   364→	evs = rangeEventsWithReuse(s.store.lg, s.store.b, evs, minRev, curRev+1)
   365→
   366→	victims := make(watcherBatch)
   367→	wb := newWatcherBatch(wg, evs)
   368→	for w := range wg.watchers {
   369→		if w.minRev < compactionRev {
   370→			// Skip the watcher that failed to send compacted watch response due to w.ch is full.
   371→			// Next retry of syncWatchers would try to resend the compacted watch response to w.ch
   372→			continue
   373→		}
   374→		w.minRev = max(curRev+1, w.minRev)
   375→
   376→		eb, ok := wb[w]
   377→		if !ok {
   378→			// bring un-notified watcher to synced
   379→			s.synced.add(w)
   380→			s.unsynced.delete(w)
   381→			continue
   382→		}
   383→
   384→		if eb.moreRev != 0 {
   385→			w.minRev = eb.moreRev
   386→		}
   387→
   388→		if w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: curRev}) {
   389→			pendingEventsGauge.Add(float64(len(eb.evs)))
   390→		} else {
   391→			w.victim = true
   392→		}
   393→
   394→		if w.victim {
   395→			victims[w] = eb
   396→		} else {
   397→			if eb.moreRev != 0 {
   398→				// stay unsynced; more to read
   399→				continue
   400→			}
   401→			s.synced.add(w)
   402→		}
   403→		s.unsynced.delete(w)
   404→	}
   405→	s.addVictim(victims)
   406→
   407→	vsz := 0
   408→	for _, v := range s.victims {
   409→		vsz += len(v)
   410→	}
   411→	slowWatcherGauge.Set(float64(s.unsynced.size() + vsz))
   412→
   413→	return s.unsynced.size(), evs
   414→}
   415→
   416→// rangeEventsWithReuse returns events in range [minRev, maxRev), while reusing already provided events.
   417→func rangeEventsWithReuse(lg *zap.Logger, b backend.Backend, evs []mvccpb.Event, minRev, maxRev int64) []mvccpb.Event {
   418→	if len(evs) == 0 {
   419→		return rangeEvents(lg, b, minRev, maxRev)
   420→	}
   421→	// append from left
   422→	if evs[0].Kv.ModRevision > minRev {
   423→		evs = append(rangeEvents(lg, b, minRev, evs[0].Kv.ModRevision), evs...)
   424→	}
   425→	// cut from left
   426→	prefixIndex := 0
   427→	for prefixIndex < len(evs) && evs[prefixIndex].Kv.ModRevision < minRev {
   428→		prefixIndex++
   429→	}
   430→	evs = evs[prefixIndex:]
   431→
   432→	if len(evs) == 0 {
   433→		return rangeEvents(lg, b, minRev, maxRev)
   434→	}
   435→	// append from right
   436→	if evs[len(evs)-1].Kv.ModRevision+1 < maxRev {
   437→		evs = append(evs, rangeEvents(lg, b, evs[len(evs)-1].Kv.ModRevision+1, maxRev)...)
   438→	}
   439→	// cut from right
   440→	suffixIndex := len(evs) - 1
   441→	for suffixIndex >= 0 && evs[suffixIndex].Kv.ModRevision >= maxRev {
   442→		suffixIndex--
   443→	}
   444→	evs = evs[:suffixIndex+1]
   445→	return evs
   446→}
   447→
   448→// rangeEvents returns events in range [minRev, maxRev).
   449→func rangeEvents(lg *zap.Logger, b backend.Backend, minRev, maxRev int64) []mvccpb.Event {
   450→	if minRev < 0 {
   451→		lg.Warn("Unexpected negative revision range start", zap.Int64("minRev", minRev))
   452→		minRev = 0
   453→	}
   454→	minBytes, maxBytes := NewRevBytes(), NewRevBytes()
   455→	minBytes = RevToBytes(Revision{Main: minRev}, minBytes)
   456→	maxBytes = RevToBytes(Revision{Main: maxRev}, maxBytes)
   457→
   458→	// UnsafeRange returns keys and values. And in boltdb, keys are revisions.
   459→	// values are actual key-value pairs in backend.
   460→	tx := b.ReadTx()
   461→	tx.RLock()
   462→	revs, vs := tx.UnsafeRange(schema.Key, minBytes, maxBytes, 0)
   463→	evs := kvsToEvents(lg, revs, vs)
   464→	// Must unlock after kvsToEvents, because vs (come from boltdb memory) is not deep copy.
   465→	// We can only unlock after Unmarshal, which will do deep copy.
   466→	// Otherwise we will trigger SIGSEGV during boltdb re-mmap.
   467→	tx.RUnlock()
   468→	return evs
   469→}
   470→
   471→// kvsToEvents gets all events for the watchers from all key-value pairs
   472→func kvsToEvents(lg *zap.Logger, revs, vals [][]byte) (evs []mvccpb.Event) {
   473→	for i, v := range vals {
   474→		var kv mvccpb.KeyValue
   475→		if err := kv.Unmarshal(v); err != nil {
   476→			lg.Panic("failed to unmarshal mvccpb.KeyValue", zap.Error(err))
   477→		}
   478→
   479→		ty := mvccpb.Event_PUT
   480→		if isTombstone(revs[i]) {
   481→			ty = mvccpb.Event_DELETE
   482→			// patch in mod revision so watchers won't skip
   483→			kv.ModRevision = BytesToRev(revs[i]).Main
   484→		}
   485→		evs = append(evs, mvccpb.Event{Kv: &kv, Type: ty})
   486→	}
   487→	return evs
   488→}
   489→
   490→// notify notifies the fact that given event at the given rev just happened to
   491→// watchers that watch on the key of the event.
   492→func (s *watchableStore) notify(rev int64, evs []mvccpb.Event) {
   493→	victim := make(watcherBatch)
   494→	for w, eb := range newWatcherBatch(&s.synced, evs) {
   495→		if eb.revs != 1 {
   496→			s.store.lg.Panic(
   497→				"unexpected multiple revisions in watch notification",
   498→				zap.Int("number-of-revisions", eb.revs),
   499→			)
   500→		}
   501→		if w.send(WatchResponse{WatchID: w.id, Events: eb.evs, Revision: rev}) {
   502→			pendingEventsGauge.Add(float64(len(eb.evs)))
   503→		} else {
   504→			// move slow watcher to victims
   505→			w.victim = true
   506→			victim[w] = eb
   507→			s.synced.delete(w)
   508→			slowWatcherGauge.Inc()
   509→		}
   510→		// always update minRev
   511→		// in case 'send' returns true and watcher stays synced, this is needed for Restore when all watchers become unsynced
   512→		// in case 'send' returns false, this is needed for syncWatchers
   513→		w.minRev = rev + 1
   514→	}
   515→	s.addVictim(victim)
   516→}
   517→
   518→func (s *watchableStore) addVictim(victim watcherBatch) {
   519→	if len(victim) == 0 {
   520→		return
   521→	}
   522→	s.victims = append(s.victims, victim)
   523→	select {
   524→	case s.victimc <- struct{}{}:
   525→	default:
   526→	}
   527→}
   528→
   529→func (s *watchableStore) rev() int64 { return s.store.Rev() }
   530→
   531→func (s *watchableStore) progress(w *watcher) {
   532→	s.progressIfSync(map[WatchID]*watcher{w.id: w}, w.id)
   533→}
   534→
   535→func (s *watchableStore) progressAll(watchers map[WatchID]*watcher) bool {
   536→	return s.progressIfSync(watchers, clientv3.InvalidWatchID)
   537→}
   538→
   539→func (s *watchableStore) progressIfSync(watchers map[WatchID]*watcher, responseWatchID WatchID) bool {
   540→	s.mu.RLock()
   541→	defer s.mu.RUnlock()
   542→
   543→	rev := s.rev()
   544→	// Any watcher unsynced?
   545→	for _, w := range watchers {
   546→		if _, ok := s.synced.watchers[w]; !ok {
   547→			return false
   548→		}
   549→		if rev < w.startRev {
   550→			return false
   551→		}
   552→	}
   553→
   554→	// If all watchers are synchronised, send out progress
   555→	// notification on first watcher. Note that all watchers
   556→	// should have the same underlying stream, and the progress
   557→	// notification will be broadcasted client-side if required
   558→	// (see dispatchEvent in client/v3/watch.go)
   559→	for _, w := range watchers {
   560→		w.send(WatchResponse{WatchID: responseWatchID, Revision: rev})
   561→		return true
   562→	}
   563→	return true
   564→}
   565→
   566→type watcher struct {
   567→	// the watcher key
   568→	key []byte
   569→	// end indicates the end of the range to watch.
   570→	// If end is set, the watcher is on a range.
   571→	end []byte
   572→
   573→	// victim is set when ch is blocked and undergoing victim processing
   574→	victim bool
   575→
   576→	// compacted is set when the watcher is removed because of compaction
   577→	compacted bool
   578→
   579→	// restore is true when the watcher is being restored from leader snapshot
   580→	// which means that this watcher has just been moved from "synced" to "unsynced"
   581→	// watcher group, possibly with a future revision when it was first added
   582→	// to the synced watcher
   583→	// "unsynced" watcher revision must always be <= current revision,
   584→	// except when the watcher were to be moved from "synced" watcher group
   585→	restore bool
   586→
   587→	startRev int64
   588→	// minRev is the minimum revision update the watcher will accept
   589→	minRev int64
   590→	id     WatchID
   591→
   592→	fcs []FilterFunc
   593→	// a chan to send out the watch response.
   594→	// The chan might be shared with other watchers.
   595→	ch chan<- WatchResponse
   596→}
   597→
   598→func (w *watcher) send(wr WatchResponse) bool {
   599→	progressEvent := len(wr.Events) == 0
   600→
   601→	if len(w.fcs) != 0 {
   602→		ne := make([]mvccpb.Event, 0, len(wr.Events))
   603→		for i := range wr.Events {
   604→			filtered := false
   605→			for _, filter := range w.fcs {
   606→				if filter(wr.Events[i]) {
   607→					filtered = true
   608→					break
   609→				}
   610→			}
   611→			if !filtered {
   612→				ne = append(ne, wr.Events[i])
   613→			}
   614→		}
   615→		wr.Events = ne
   616→	}
   617→
   618→	verify.Verify("Event.ModRevision is less than the w.startRev for watchID", func() (bool, map[string]any) {
   619→		if w.startRev > 0 {
   620→			for _, ev := range wr.Events {
   621→				if ev.Kv.ModRevision < w.startRev {
   622→					return false, map[string]any{
   623→						"Event.ModRevision": ev.Kv.ModRevision,
   624→						"w.startRev":        w.startRev,
   625→						"watchID":           w.id,
   626→					}
   627→				}
   628→			}
   629→		}
   630→		return true, nil
   631→	})
   632→
   633→	// if all events are filtered out, we should send nothing.
   634→	if !progressEvent && len(wr.Events) == 0 {
   635→		return true
   636→	}
   637→	select {
   638→	case w.ch <- wr:
   639→		return true
   640→	default:
   641→		return false
   642→	}
   643→}
   644→

