   222→// syncWatchersLoop syncs the watcher in the unsynced map every 100ms.
   223→func (s *watchableStore) syncWatchersLoop() {
   224→	defer s.wg.Done()
   225→
   226→	delayTicker := time.NewTicker(watchResyncPeriod)
   227→	defer delayTicker.Stop()
   228→	var evs []mvccpb.Event
   229→
   230→	for {
   231→		s.mu.RLock()
   232→		st := time.Now()
   233→		lastUnsyncedWatchers := s.unsynced.size()
   234→		s.mu.RUnlock()
   235→
   236→		unsyncedWatchers := 0
   237→		if lastUnsyncedWatchers > 0 {
   238→			unsyncedWatchers, evs = s.syncWatchers(evs)
   239→		}
   240→		syncDuration := time.Since(st)
   241→
   242→		delayTicker.Reset(watchResyncPeriod)
   243→		// more work pending?
   244→		if unsyncedWatchers != 0 && lastUnsyncedWatchers > unsyncedWatchers {
   245→			// be fair to other store operations by yielding time taken
   246→			delayTicker.Reset(syncDuration)
   247→		}
   248→
   249→		select {
   250→		case <-delayTicker.C:
   251→		case <-s.stopc:
   252→			return
   253→		}
   254→	}
   255→}
