func UnsafeSetScheduledCompact(tx backend.UnsafeWriter, value int64) {
	rbytes := NewRevBytes()
	rbytes = RevToBytes(Revision{Main: value}, rbytes)
	tx.UnsafePut(schema.Meta, schema.ScheduledCompactKeyName, rbytes)
}

